// ============================================================
// IoT Device Client (HTTP/HTTPS - local network)
// ============================================================
const iotClient = {
  _buildDeviceUrl: (deviceIp, endpoint, protocol = 'http') => {
    // Validate IP format
    const ipRegex = /^192\.168\.\d{1,3}\.\d{1,3}$/;
    if (!ipRegex.test(deviceIp)) {
      throw new NetworkError(
        `Invalid IoT device IP: ${deviceIp}. Expected format: 192.168.x.x`,
        0,
        'INVALID_DEVICE_IP'
      );
    }
    return `${protocol}://${deviceIp}${endpoint}`;
  },

  get: async (deviceIp, endpoint = '/', options = {}) => {
    const protocol = options.useHttps ? 'https' : 'http';
    const url = iotClient._buildDeviceUrl(deviceIp, endpoint, protocol);

    const params = options.params || {};
    const queryString = Object.keys(params).length
      ? '?' + new URLSearchParams(params).toString()
      : '';

    const request = () =>
      fetchWithTimeout(
        `${url}${queryString}`,
        {
          method: 'GET',
          headers: buildIoTHeaders(options.headers),
          signal: options.signal,
        },
        options.timeout || IOT_DEVICE_TIMEOUT
      ).then(handleIoTResponse);

    return options.retry === false ? request() : withRetry(request, options.maxRetries || 2, 500);
  },

  post: async (deviceIp, endpoint = '/', body = {}, options = {}) => {
    const protocol = options.useHttps ? 'https' : 'http';
    const url = iotClient._buildDeviceUrl(deviceIp, endpoint, protocol);

    const request = () =>
      fetchWithTimeout(
        url,
        {
          method: 'POST',
          headers: buildIoTHeaders(options.headers),
          body: JSON.stringify(body),
          signal: options.signal,
        },
        options.timeout || IOT_DEVICE_TIMEOUT
      ).then(handleIoTResponse);

    return options.retry === false ? request() : withRetry(request, options.maxRetries || 2, 500);
  },

  put: async (deviceIp, endpoint = '/', body = {}, options = {}) => {
    const protocol = options.useHttps ? 'https' : 'http';
    const url = iotClient._buildDeviceUrl(deviceIp, endpoint, protocol);

    const request = () =>
      fetchWithTimeout(
        url,
        {
          method: 'PUT',
          headers: buildIoTHeaders(options.headers),
          body: JSON.stringify(body),
          signal: options.signal,
        },
        options.timeout || IOT_DEVICE_TIMEOUT
      ).then(handleIoTResponse);

    return options.retry === false ? request() : withRetry(request, options.maxRetries || 2, 500);
  },

  delete: async (deviceIp, endpoint = '/', options = {}) => {
    const protocol = options.useHttps ? 'https' : 'http';
    const url = iotClient._buildDeviceUrl(deviceIp, endpoint, protocol);

    const request = () =>
      fetchWithTimeout(
        url,
        {
          method: 'DELETE',
          headers: buildIoTHeaders(options.headers),
          signal: options.signal,
        },
        options.timeout || IOT_DEVICE_TIMEOUT
      ).then(handleIoTResponse);

    return options.retry === false ? request() : withRetry(request, options.maxRetries || 1, 500);
  },

  // Discover / ping a device on the local network
  ping: async (deviceIp, options = {}) => {
    const protocol = options.useHttps ? 'https' : 'http';
    try {
      const url = iotClient._buildDeviceUrl(deviceIp, options.healthEndpoint || '/status', protocol);
      const startTime = Date.now();

      const response = await fetchWithTimeout(
        url,
        {
          method: 'GET',
          headers: buildIoTHeaders(),
        },
        options.timeout || 3000
      );

      const latency = Date.now() - startTime;
      const data = await response.json().catch(() => null);

      return {
        reachable: response.ok,
        latency,
        status: response.status,
        data,
        ip: deviceIp,
        protocol,
      };
    } catch (error) {
      return {
        reachable: false,
        latency: null,
        status: null,
        data: null,
        ip: deviceIp,
        protocol,
        error: error.message,
      };
    }
  },

  // Scan a range of IPs on 192.168.x subnet for IoT devices
  scanSubnet: async (subnet = '192.168.1', startIp = 1, endIp = 254, options = {}) => {
    const concurrency = options.concurrency || 20;
    const devices = [];
    const ips = [];

    for (let i = startIp; i <= endIp; i++) {
      ips.push(`${subnet}.${i}`);
    }

    // Process in batches to avoid overwhelming the network
    for (let i = 0; i < ips.length; i += concurrency) {
      const batch = ips.slice(i, i + concurrency);
      const results = await Promise.all(
        batch.map((ip) => iotClient.ping(ip, { timeout: options.timeout || 2000, ...options }))
      );

      results.forEach((result) => {
        if (result.reachable) {
          devices.push(result);
        }
      });

      if (options.onProgress) {
        options.onProgress({
          scanned: Math.min(i + concurrency, ips.length),
          total: ips.length,
          found: devices.length,
        });
      }
    }

    return devices;
  },
};

// ============================================================
// Request Interceptors / Logging
