const enableLogging = (enabled = true) => {
  if (enabled) {
    const originalFetch = global.fetch;
    global.fetch = async (...args) => {
      const [url, config] = args;
      const method = config?.method || 'GET';
      const startTime = Date.now();

      console.log(`[NetworkModule] → ${method} ${url}`);

      try {
        const response = await originalFetch(...args);
        const duration = Date.now() - startTime;
        console.log(`[NetworkModule] ← ${response.status} ${method} ${url} (${duration}ms)`);
        return response;
      } catch (error) {
        const duration = Date.now() - startTime;
        console.error(`[NetworkModule] ✗ ${method} ${url} (${duration}ms): ${error.message}`);
        throw error;
      }
    };

    console.log('[NetworkModule] Logging enabled');
  }
};

