// Connection checker utility
// ============================================================
const checkConnectivity = async () => {
  const results = {
    api: false,
    apiLatency: null,
    timestamp: new Date().toISOString(),
  };

  try {
    const startTime = Date.now();
    const response = await fetchWithTimeout(
      `${API_BASE_URL}/health`,
      { method: 'GET', headers: buildApiHeaders() },
      5000
    );
    results.api = response.ok;
    results.apiLatency = Date.now() - startTime;
  } catch (_) {
    results.api = false;
  }

  return results;
};

